import React from 'react';
import './FlipCard.css';

const FlipCard = ({ 
  image, 
  title, 
  buttonText = "Купить", 
  onButtonClick 
}) => {
  return (
    <div className="card">
      <div className="card-inner">
        <div className="card-front">
          <img src={image} />
          <h2>{title}</h2>
        </div>
        <div className="card-back">
          <img src={image} alt={title} />          
          <h2>{title}</h2>
          <button onClick={onButtonClick}>{buttonText}</button>
        </div>
      </div>
    </div>
  );
};

export default FlipCard;
